#pragma once

#include <llvm/IR/PassManager.h>

/// A combined "instcombine + simplify-cfg + GVN-lite + DCE" pass.
///
/// It iterates the following transformations on the whole module until a
/// fixed-point is reached:
///   * algebraic identities (x*0, x*1, x+0, x-0, x-x, x/1, x%1, 0*x, 0/x ...)
///   * constant folding for binary ops, comparisons, casts, GEPs
///   * re-association of `(x op c1) op c2` into `x op (c1 op c2)`
///   * common subexpression elimination within each basic block
///   * load forwarding (same address + no intervening write in the BB)
///   * dead code elimination (instructions with no users and no side effects)
class Simplify : public llvm::PassInfoMixin<Simplify>
{
public:
  llvm::PreservedAnalyses run(llvm::Module& mod,
                              llvm::ModuleAnalysisManager& mam);
};
